create table if not exists analytics.export_audits (id bigserial primary key, export_id text not null unique, module text not null, requested_by text not null, filters jsonb not null default '{}'::jsonb, definitions_included boolean not null default true, trust_labels_included boolean not null default true, freshness_included boolean not null default true, formula_versions_included boolean not null default true, owner_included boolean not null default true, fingerprint text not null, audit_reference text not null, created_at timestamptz not null default now());
